import{_ as t,o as e,c as i,ae as s}from"./chunks/framework.DTwQaIIa.js";const k=JSON.parse('{"title":"项目介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),n={name:"guide/introduction.md"};function d(o,a,r,l,c,p){return e(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="项目介绍" tabindex="-1">项目介绍 <a class="header-anchor" href="#项目介绍" aria-label="Permalink to &quot;项目介绍&quot;">​</a></h1><p>Emaki Series 是一套 Minecraft Spigot 服务端的 RPG 插件，用 Java 编写，以多模块 Maven 工程组织。整套插件围绕 <code>EmakiCoreLib</code> 这个核心库展开——属性战斗、锻造、强化、烹饪、宝石镶嵌、主动技能，每个玩法都是一个独立模块，按需组合。</p><h2 id="项目快照" tabindex="-1">项目快照 <a class="header-anchor" href="#项目快照" aria-label="Permalink to &quot;项目快照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目属性</th><th>详情</th></tr></thead><tbody><tr><td>项目类型</td><td>Minecraft Spigot 多模块 Java 插件工程</td></tr><tr><td>Java 基线</td><td><code>21</code></td></tr><tr><td>API 基线</td><td><code>Spigot API 1.21.11-R0.1-SNAPSHOT</code></td></tr><tr><td>文本组件</td><td><code>Adventure 4.26.1</code></td></tr><tr><td>构建工具</td><td>Maven 多模块聚合</td></tr><tr><td>许可证</td><td><code>GPL-3.0-only</code></td></tr><tr><td>仓库地址</td><td><a href="https://github.com/jiuwu02/Emaki_Series" target="_blank" rel="noreferrer">GitHub</a></td></tr></tbody></table><h2 id="当前版本线" tabindex="-1">当前版本线 <a class="header-anchor" href="#当前版本线" aria-label="Permalink to &quot;当前版本线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>artifactId</th><th>版本</th></tr></thead><tbody><tr><td>EmakiCoreLib</td><td><code>emaki-corelib</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiAttribute</td><td><code>emaki-attribute</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiForge</td><td><code>emaki-forge</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiStrengthen</td><td><code>emaki-strengthen</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiCooking</td><td><code>emaki-cooking</code></td><td><code>2.0.0</code></td></tr><tr><td>EmakiGem</td><td><code>emaki-gem</code></td><td><code>1.2.0</code></td></tr><tr><td>EmakiSkills</td><td><code>emaki-skills</code></td><td><code>1.0.0</code></td></tr></tbody></table><h2 id="模块关系" tabindex="-1">模块关系 <a class="header-anchor" href="#模块关系" aria-label="Permalink to &quot;模块关系&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EmakiCoreLib</span></span>
<span class="line"><span>├── EmakiAttribute</span></span>
<span class="line"><span>├── EmakiForge</span></span>
<span class="line"><span>├── EmakiStrengthen</span></span>
<span class="line"><span>├── EmakiCooking</span></span>
<span class="line"><span>├── EmakiGem</span></span>
<span class="line"><span>└── EmakiSkills</span></span></code></pre></div><p>所有业务模块都强依赖 <code>EmakiCoreLib</code>，它负责 GUI、动作执行、物品源、配置管理、经济接口、PDC 读写和运行时服务这些底层工作。之所以把这些东西集中到一个库里，是为了让各模块在操作物品时共享同一套&quot;层快照 → 重建展示&quot;的流程，避免模块之间互相覆盖物品数据。</p><p>各模块之间的协作关系：</p><ul><li><strong>EmakiAttribute</strong> 独立处理属性定义和战斗计算。Forge、Strengthen、Gem 可以通过 PDC 把属性写进物品，Attribute 会自动识别并纳入计算。</li><li><strong>EmakiForge</strong> 通过 CoreLib 装配物品、读取材料来源，锻造产物可以选择性地携带 Attribute 属性数据。</li><li><strong>EmakiStrengthen</strong> 用配方系统给装备叠加强化层，强化产生的属性同样可以接入 Attribute。</li><li><strong>EmakiCooking</strong> 走的是&quot;世界工位&quot;路线——四类厨具放在世界里，玩家直接交互。它依赖 CoreLib 的物品源、动作系统和方块桥接来识别工位和处理配方。</li><li><strong>EmakiGem</strong> 通过装备模板、开孔器和宝石定义实现可组合的装备成长线，宝石属性同样可以接入 Attribute。</li><li><strong>EmakiSkills</strong> 管理技能的解锁、槽位、触发器和施法模式，但技能效果本身由 MythicMobs 配置驱动。换句话说，Skills 是&quot;技能管理框架&quot;，不是&quot;技能效果引擎&quot;。</li></ul><h2 id="仓库结构" tabindex="-1">仓库结构 <a class="header-anchor" href="#仓库结构" aria-label="Permalink to &quot;仓库结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Project/</span></span>
<span class="line"><span>├── EmakiCoreLib/        # 核心基础库</span></span>
<span class="line"><span>├── EmakiAttribute/      # 属性与战斗系统</span></span>
<span class="line"><span>├── EmakiForge/          # 锻造系统</span></span>
<span class="line"><span>├── EmakiStrengthen/     # 强化系统</span></span>
<span class="line"><span>├── EmakiCooking/        # 烹饪系统</span></span>
<span class="line"><span>├── EmakiGem/            # 装备宝石系统</span></span>
<span class="line"><span>├── EmakiSkills/         # 主动技能系统</span></span>
<span class="line"><span>└── pom.xml              # Maven 父工程</span></span></code></pre></div><h2 id="构建方式" tabindex="-1">构建方式 <a class="header-anchor" href="#构建方式" aria-label="Permalink to &quot;构建方式&quot;">​</a></h2><p>根 <code>pom.xml</code> 默认聚合五个开源模块：<code>EmakiCoreLib</code>、<code>EmakiAttribute</code>、<code>EmakiForge</code>、<code>EmakiStrengthen</code>、<code>EmakiCooking</code>。如果根目录下存在 <code>.key</code> 文件，<code>private-modules</code> profile 会额外纳入 <code>EmakiGem</code> 和 <code>EmakiSkills</code>——这两个是闭源模块，需要授权才能构建。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 完整构建</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clean</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 只做编译检查，跳过测试</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -DskipTests</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span></span></code></pre></div><p>构建完成后，各模块的 jar 会输出到对应模块的 <code>target/</code> 目录。</p><h2 id="社区" tabindex="-1">社区 <a class="header-anchor" href="#社区" aria-label="Permalink to &quot;社区&quot;">​</a></h2><ul><li><a href="https://github.com/jiuwu02/Emaki_Series" target="_blank" rel="noreferrer">GitHub 仓库</a></li><li><a href="https://discord.gg/FV4GFQbvCM" target="_blank" rel="noreferrer">Discord 社区</a></li><li><a href="https://qm.qq.com/q/GqGrzHp0wU" target="_blank" rel="noreferrer">QQ 群</a></li></ul>`,19)])])}const m=t(n,[["render",d]]);export{k as __pageData,m as default};
